    '/w/{workspace}/assets/list': {
        get: {
            req: {
                /**
                 * Filter by asset kinds (multiple values allowed)
                 */
                assetKinds?: string;
                /**
                 * Filter by asset path (case-insensitive partial match)
                 */
                assetPath?: string;
                /**
                 * broad search across multiple fields (case-insensitive substring match)
                 */
                broadFilter?: string;
                /**
                 * JSONB subset match filter for columns using base64 encoded JSON
                 */
                columns?: string;
                /**
                 * Cursor timestamp for pagination (created_at of last item from previous page)
                 */
                cursorCreatedAt?: string;
                /**
                 * Cursor ID for pagination (id of last item from previous page)
                 */
                cursorId?: number;
                /**
                 * exact path match filter
                 */
                path?: string;
                /**
                 * Number of items per page (max 1000, default 50)
                 */
                perPage?: number;
                /**
                 * Filter by usage path (case-insensitive partial match)
                 */
                usagePath?: string;
                workspace: string;
            };
            res: {
                /**
                 * paginated assets in the workspace
                 */
                200: {
                    assets: Array<{
                        path: string;
                        kind: AssetKind;
                        usages: Array<{
                            path: string;
                            kind: AssetUsageKind;
                            access_type?: AssetUsageAccessType;
                            /**
                             * The columns used (for tables)
                             */
                            columns?: {
                                [key: string]: AssetUsageAccessType;
                            };
                            /**
                             * When the asset was detected
                             */
                            created_at?: string;
                            metadata?: {
                                /**
                                 * The path of the script/flow that was run (only present when kind is 'job')
                                 */
                                runnable_path?: string;
                                /**
                                 * The kind of job (script, flow, preview, etc.) (only present when kind is 'job')
                                 */
                                job_kind?: string;
                            };
                        }>;
                        metadata?: {
                            /**
                             * The type of the resource (only present when kind is 'resource')
                             */
                            resource_type?: string;
                        };
                    }>;
                    /**
                     * Cursor for the next page (null if no more pages)
                     */
                    next_cursor?: {
                        /**
                         * Timestamp to use for next page
                         */
                        created_at?: string;
                        /**
                         * ID to use for next page
                         */
                        id?: number;
                    } | null;
                };
            };
        };
    };
